<?php
declare(strict_types=1);
function booking_type(string $slug):array{$q=db()->prepare('SELECT m.*,c.name calendar_name,c.timezone calendar_timezone,c.owner_user_id FROM booking_meeting_types m JOIN booking_calendars c ON c.id=m.calendar_id WHERE m.slug=? AND m.active=1 AND c.active=1');$q->execute([$slug]);$r=$q->fetch();if(!$r){http_response_code(404);exit('Booking page not found');}return $r;}
function booking_native_slots(array $type,int $days=21):array{$tz=new DateTimeZone($type['calendar_timezone']);$now=new DateTimeImmutable('now',$tz);$from=$now->modify('+'.(int)$type['minimum_notice_hours'].' hours');$rules=db()->prepare('SELECT * FROM booking_availability_rules WHERE calendar_id=? ORDER BY weekday,start_time');$rules->execute([$type['calendar_id']]);$by=[];foreach($rules->fetchAll() as $r)$by[(int)$r['weekday']][]=$r;$busy=db()->prepare("SELECT starts_at,ends_at FROM bookings WHERE calendar_id=? AND status='confirmed' AND starts_at BETWEEN ? AND ?");$busy->execute([$type['calendar_id'],$now->format('Y-m-d H:i:s'),$now->modify("+$days days")->format('Y-m-d H:i:s')]);$booked=$busy->fetchAll();$out=[];for($i=0;$i<$days;$i++){$day=$now->setTime(0,0)->modify("+$i days");foreach($by[(int)$day->format('w')]??[] as $rule){$cursor=new DateTimeImmutable($day->format('Y-m-d').' '.$rule['start_time'],$tz);$end=new DateTimeImmutable($day->format('Y-m-d').' '.$rule['end_time'],$tz);while($cursor->modify('+'.(int)$type['duration_minutes'].' minutes')<=$end){$slotEnd=$cursor->modify('+'.(int)$type['duration_minutes'].' minutes');$conflict=false;foreach($booked as $b)if($cursor<new DateTimeImmutable($b['ends_at'],$tz)&&$slotEnd>new DateTimeImmutable($b['starts_at'],$tz)){$conflict=true;break;}if(!$conflict&&$cursor>=$from)$out[]=$cursor;$cursor=$cursor->modify('+'.(int)$type['duration_minutes'].' minutes');}}}return array_slice($out,0,120);}
function booking_filter_external_busy(array $type,array $slots):array{$uid=(int)($type['owner_user_id']??0);if(!$uid&&!empty($type['calendar_id'])){$q=db()->prepare('SELECT owner_user_id FROM booking_calendars WHERE id=?');$q->execute([(int)$type['calendar_id']]);$uid=(int)$q->fetchColumn();}if(!$uid||!$slots)return $slots;$duration=(int)$type['duration_minutes'];$last=$slots[array_key_last($slots)];$busy=calendar_busy_ranges($uid,$slots[0]->modify('-1 day'),$last->modify('+1 day'));return array_values(array_filter($slots,function(DateTimeImmutable $slot)use($busy,$duration){$end=$slot->modify("+$duration minutes");foreach($busy as [$from,$to])if($slot<$to&&$end>$from)return false;return true;}));}
function booking_slots(array $type,int $days=21):array{if(!ea_enabled())return booking_filter_external_busy($type,booking_native_slots($type,$days));$tz=new DateTimeZone($type['calendar_timezone']);$now=new DateTimeImmutable('now',$tz);$from=$now->modify('+'.(int)$type['minimum_notice_hours'].' hours');$out=[];for($i=0;$i<$days;$i++){$day=$now->modify("+$i days");foreach(ea_availability($type,$day->format('Y-m-d')) as $time){$slot=new DateTimeImmutable($day->format('Y-m-d').' '.$time,$tz);if($slot>=$from)$out[]=$slot;}}return array_slice(booking_filter_external_busy($type,$out),0,120);}
if(preg_match('#^/book/([a-z0-9_-]+)$#',$path,$m)){$type=booking_type($m[1]);$slots=booking_slots($type);$qq=db()->prepare('SELECT * FROM booking_questions WHERE meeting_type_id=? ORDER BY position,id');$qq->execute([$type['id']]);$questions=$qq->fetchAll();if($method==='POST'){verify_csrf();$email=strtolower(trim((string)post('email')));$name=trim((string)post('name'));$startRaw=(string)post('starts_at');$valid=null;foreach($slots as $slot)if(hash_equals($slot->format(DateTimeInterface::ATOM),$startRaw)){$valid=$slot;break;}if(!$valid||!filter_var($email,FILTER_VALIDATE_EMAIL)||$name===''){flash('error','Choose an available time and enter your name and email.');redirect('/book/'.$type['slug']);}$answers=[];foreach($questions as $question){$value=trim((string)post('question_'.$question['field_key']));if($question['required']&&$value===''){flash('error',$question['label'].' is required.');redirect('/book/'.$type['slug']);}$answers[$question['field_key']]=$value;}$end=$valid->modify('+'.(int)$type['duration_minutes'].' minutes');$q=db()->prepare('SELECT * FROM contacts WHERE LOWER(email)=? LIMIT 1');$q->execute([$email]);$contact=$q->fetch();$parts=preg_split('/\s+/',$name,2);if(!$contact){db()->prepare('INSERT INTO contacts(first_name,last_name,email,phone,active,created_by,owner_id) VALUES(?,?,?,?,1,?,?)')->execute([$parts[0],$parts[1]??'Booking',$email,trim((string)post('phone'))?:null,$type['owner_user_id'],$type['owner_user_id']]);$contactId=(int)db()->lastInsertId();}else $contactId=(int)$contact['id'];$visitor=$_COOKIE['oc_vid']??'';$session=$_COOKIE['oc_sid']??'';$sid=null;if($session){$sq=db()->prepare('SELECT id FROM site_sessions WHERE session_key=?');$sq->execute([$session]);$sid=$sq->fetchColumn()?:null;}db()->prepare('INSERT INTO bookings(meeting_type_id,calendar_id,assigned_user_id,contact_id,session_id,attendee_name,attendee_email,attendee_phone,starts_at,ends_at,timezone,answers_json,cancel_token) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)')->execute([$type['id'],$type['calendar_id'],$type['owner_user_id'],$contactId,$sid,$name,$email,trim((string)post('phone'))?:null,$valid->format('Y-m-d H:i:s'),$end->format('Y-m-d H:i:s'),$type['calendar_timezone'],json_encode($answers),bin2hex(random_bytes(32))]);$bookingId=(int)db()->lastInsertId();$externalId=ea_enabled()?ea_create_appointment($type,$name,$email,trim((string)post('phone')),$valid,$end):0;if($externalId)db()->prepare('UPDATE bookings SET external_appointment_id=? WHERE id=?')->execute([$externalId,$bookingId]);booking_send_confirmation($bookingId);booking_schedule_reminders($bookingId);if($visitor)db()->prepare('UPDATE site_visitors SET contact_id=? WHERE visitor_key=?')->execute([$contactId,$visitor]);if($sid)db()->prepare("INSERT INTO site_conversions(session_id,contact_id,conversion_type,entity_type,entity_id,metadata_json) VALUES(?,?,'booking','booking',?,?)")->execute([$sid,$contactId,$bookingId,json_encode(['meeting_type'=>$type['name']])]);db()->prepare('INSERT INTO notes(contact_id,user_id,body) VALUES(?,?,?)')->execute([$contactId,$type['owner_user_id'],"Booked {$type['name']} for ".$valid->format('M j, Y g:i A').' '.$type['calendar_timezone']]);foreach(array_map('intval',json_decode((string)$type['tag_ids'],true)?:[]) as $tag)db()->prepare('INSERT IGNORE INTO contact_tags(contact_id,tag_id) VALUES(?,?)')->execute([$contactId,$tag]);audit('create','booking',$bookingId,['contact_id'=>$contactId]);layout('Booking confirmed',function()use($type,$valid){?><div class="card login"><h1>Meeting confirmed</h1><p><strong><?=e($type['name'])?></strong></p><p><?=e($valid->format('l, F j, Y \a\t g:i A'))?> <?=e($type['calendar_timezone'])?></p></div><?php });exit;}layout($type['name'],function()use($type,$slots,$questions){?><div class="card login"><h1><?=e($type['name'])?></h1><p><?=nl2br(e($type['description']))?></p><p><?=e($type['duration_minutes'])?> minutes · <?=e($type['location_details'])?></p><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><label>Available time<select name="starts_at" required><option value="">Choose a time…</option><?php foreach($slots as $slot):?><option value="<?=e($slot->format(DateTimeInterface::ATOM))?>"><?=e($slot->format('D, M j · g:i A'))?></option><?php endforeach?></select></label><label>Name<input name="name" required></label><label>Email<input type="email" name="email" required></label><label>Phone<input type="tel" name="phone"></label><?php foreach($questions as $question):$options=json_decode((string)$question['options_json'],true)?:[];?><label><?=e($question['label'])?><?php if($question['field_type']==='textarea'):?><textarea name="question_<?=e($question['field_key'])?>" <?=$question['required']?'required':''?>></textarea><?php elseif($question['field_type']==='select'):?><select name="question_<?=e($question['field_key'])?>" <?=$question['required']?'required':''?>><option value="">Choose…</option><?php foreach($options as $option):?><option><?=e($option)?></option><?php endforeach?></select><?php elseif($question['field_type']==='checkbox'):?><input type="checkbox" name="question_<?=e($question['field_key'])?>" value="Yes" <?=$question['required']?'required':''?>><?php else:?><input name="question_<?=e($question['field_key'])?>" <?=$question['required']?'required':''?>><?php endif?></label><?php endforeach?><button>Book meeting</button></form></div><?php });exit;}
if(!str_starts_with($path,'/bookings'))return;require_permission('bookings.view');
if($path==='/bookings'){$rows=db()->query('SELECT b.*,m.name meeting_name,COALESCE(NULLIF(u.display_name,\'\'),u.username) assigned_name FROM bookings b JOIN booking_meeting_types m ON m.id=b.meeting_type_id LEFT JOIN users u ON u.id=b.assigned_user_id ORDER BY b.starts_at DESC LIMIT 500')->fetchAll();$types=db()->query('SELECT m.*,c.name calendar_name FROM booking_meeting_types m JOIN booking_calendars c ON c.id=m.calendar_id ORDER BY m.name')->fetchAll();layout('Bookings',function()use($rows,$types){?><div class="actions"><h1 style="margin:0">Bookings</h1><span class="spacer"></span><?php if(can('bookings.edit')):?><a class="btn" href="/bookings/calendars">Manage calendars</a><?php endif?></div><div class="card"><h2>Booking pages</h2><?php foreach($types as $t):?><p><a target="_blank" href="/book/<?=e($t['slug'])?>"><?=e($t['name'])?></a> <span class="muted">· <?=e($t['calendar_name'])?></span></p><?php endforeach?></div><div class="card"><table><thead><tr><th>When</th><th>Meeting</th><th>Attendee</th><th>Assigned</th><th>Status</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['starts_at'])?></td><td><?=e($r['meeting_name'])?></td><td><?=e($r['attendee_name'])?><br><?=e($r['attendee_email'])?></td><td><?=e($r['assigned_name']?:'—')?></td><td><?=e($r['status'])?></td></tr><?php endforeach?></tbody></table></div><?php });exit;}
if($path==='/bookings/calendars'){require_permission('bookings.edit');if($method==='POST'){verify_csrf();$a=(string)post('action');if($a==='calendar'){db()->prepare('INSERT INTO booking_calendars(name,owner_user_id,calendar_type,timezone,created_by) VALUES(?,?,?,?,?)')->execute([trim((string)post('name')),(int)post('owner_user_id')?:null,post('calendar_type'),post('timezone'),user()['id']]);$id=(int)db()->lastInsertId();foreach([1,2,3,4,5] as $day)db()->prepare('INSERT INTO booking_availability_rules(calendar_id,weekday,start_time,end_time) VALUES(?,?,\'09:00:00\',\'17:00:00\')')->execute([$id,$day]);}elseif($a==='meeting'){db()->prepare('INSERT INTO booking_meeting_types(calendar_id,name,slug,description,duration_minutes,minimum_notice_hours,location_type,location_details,tag_ids,created_by) VALUES(?,?,?,?,?,?,?,?,?,?)')->execute([(int)post('calendar_id'),trim((string)post('name')),trim(strtolower(preg_replace('/[^a-z0-9_-]+/i','-',(string)post('slug'))),'-'),trim((string)post('description')),max(5,(int)post('duration_minutes')),max(0,(int)post('minimum_notice_hours')),post('location_type'),trim((string)post('location_details')),json_encode(array_map('intval',(array)post('tag_ids',[]))),user()['id']]);}audit('create','booking_'.$a,(int)db()->lastInsertId());redirect('/bookings/calendars');}$calendars=db()->query('SELECT c.*,COALESCE(NULLIF(u.display_name,\'\'),u.username) owner_name FROM booking_calendars c LEFT JOIN users u ON u.id=c.owner_user_id ORDER BY c.name')->fetchAll();$users=db()->query('SELECT id,COALESCE(NULLIF(display_name,\'\'),username) name FROM users WHERE active=1 ORDER BY name')->fetchAll();$tags=all_tags();layout('Booking calendars',function()use($calendars,$users,$tags){?><h1>Booking calendars</h1><div class="grid"><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="calendar"><h2>Create calendar</h2><label>Name<input name="name" required></label><label>Owner<select name="owner_user_id"><?php foreach($users as $u):?><option value="<?=$u['id']?>"><?=e($u['name'])?></option><?php endforeach?></select></label><label>Type<select name="calendar_type"><option value="individual">Individual</option><option value="round_robin">Round robin</option><option value="collective">Collective</option></select></label><label>Timezone<select name="timezone"><?php foreach(timezone_identifiers_list() as $tz):?><option <?=$tz==='America/New_York'?'selected':''?>><?=e($tz)?></option><?php endforeach?></select></label><button>Create calendar</button></form><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="meeting"><h2>Create meeting type</h2><label>Calendar<select name="calendar_id"><?php foreach($calendars as $c):?><option value="<?=$c['id']?>"><?=e($c['name'])?></option><?php endforeach?></select></label><label>Name<input name="name" required></label><label>Public URL code<input name="slug" required></label><label>Description<textarea name="description"></textarea></label><label>Duration (minutes)<input type="number" name="duration_minutes" value="30" min="5"></label><label>Minimum notice (hours)<input type="number" name="minimum_notice_hours" value="4" min="0"></label><label>Location<select name="location_type"><option value="video">Video</option><option value="phone">Phone</option><option value="in_person">In person</option><option value="custom">Custom</option></select></label><label>Location details<input name="location_details"></label><label>Tags<select multiple name="tag_ids[]"><?php foreach($tags as $t):?><option value="<?=$t['id']?>"><?=e($t['name'])?></option><?php endforeach?></select></label><button>Create booking page</button></form></div><div class="card"><h2>Calendars</h2><table><tbody><?php foreach($calendars as $c):?><tr><td><?=e($c['name'])?></td><td><?=e($c['owner_name'])?></td><td><?=e($c['calendar_type'])?></td><td><?=e($c['timezone'])?></td></tr><?php endforeach?></tbody></table></div><?php });exit;}
